 public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };

     [McpServerTool, Description("Get current weather conditions for a location using latitude and longitude.")]
     public async Task<string> GetCurrentWeather(
         [Description("Latitude of the location (e.g. 47.6062 for Seattle)")] double latitude,
         [Description("Longitude of the location (e.g. -122.3321 for Seattle)")] double longitude,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

         var url = $"https://api.open-meteo.com/v1/forecast"
             + $"?latitude={latitude}&longitude={longitude}"
             + $"&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

         var response = await httpClient.GetStringAsync(url, cancellationToken);

         using var doc = JsonDocument.Parse(response);
         var current = doc.RootElement.GetProperty("current");

         var temp = current.GetProperty("temperature_2m").GetDouble();
         var wind = current.GetProperty("wind_speed_10m").GetDouble();
         var humidity = current.GetProperty("relative_humidity_2m").GetInt32();

         return $"Temperature: {temp}°C, Wind: {wind} km/h, Humidity: {humidity}%";
     }

     [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
     public async Task<string> GetForecast(
         [Description("Latitude of the location")] double latitude,
         [Description("Longitude of the location")] double longitude,
         [Description("Number of forecast days (1-7)")] int days = 3,
         CancellationToken cancellationToken = default)
     {
         days = Math.Clamp(days, 1, 7);

         var url = $"https://api.open-meteo.com/v1/forecast"
             + $"?latitude={latitude}&longitude={longitude}"
             + $"&daily=temperature_2m_max,temperature_2m_min,precipitation_sum"
             + $"&forecast_days={days}";

         var response = await httpClient.GetStringAsync(url, cancellationToken);

         using var doc = JsonDocument.Parse(response);
         var daily = doc.RootElement.GetProperty("daily");

         var dates = daily.GetProperty("time").EnumerateArray();
         var highs = daily.GetProperty("temperature_2m_max").EnumerateArray();
         var lows = daily.GetProperty("temperature_2m_min").EnumerateArray();
         var precip = daily.GetProperty("precipitation_sum").EnumerateArray();

         var lines = dates.Zip(highs, (d, h) => (d, h))
             .Zip(lows, (pair, l) => (pair.d, pair.h, l))
             .Zip(precip, (tuple, p) => (tuple.d, tuple.h, tuple.l, p))
             .Select(x =>
                 $"{x.d.GetString()}: High {x.h.GetDouble()}°C, Low {x.l.GetDouble()}°C, Precip {x.p.GetDouble()} mm");

         return string.Join('\n', lines);
     }
 }
